            </div>
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            <div>
              <Label className="text-xs text-gray-400">Images</Label>
              <div className="mt-2">
                <UnifiedSelect
                  value={imageMode}
                  onValueChange={(v: string): void => setImageMode(v as "links" | "download")}
                  options={[
                    { value: "links", label: "Import image links" },
                    { value: "download", label: "Download product images" }
                  ]}
                  triggerClassName="w-full bg-gray-900 border-border text-sm text-white h-9"
                />
              </div>
              <p className="mt-2 text-xs text-gray-500">
                Image links keep Base.com URLs. Download stores images in your
                uploads folder.
              </p>
            </div>
            <div>
              <Label className="text-xs text-gray-400">SKU Handling</Label>
              <div className="mt-2 flex items-center gap-2">
                <Checkbox
                  id="allowDuplicateSku"
                  checked={allowDuplicateSku}
                  onCheckedChange={(checked: boolean | "indeterminate"): void =>
                    setAllowDuplicateSku(Boolean(checked))
                  }
                  className="h-4 w-4 rounded border bg-gray-900 text-blue-500"
                />
                <Label
                  htmlFor="allowDuplicateSku"
                  className="text-sm text-white"
                >
                  Allow duplicate SKUs
                </Label>
              </div>
              <p className="mt-2 text-xs text-gray-500">
                When unchecked, products with existing SKUs will be skipped.
              </p>
            </div>
          </div>

          <div className="flex items-center justify-between gap-4">
            <p className="text-xs text-gray-500">
              Default catalog and price group must be configured before import.
            </p>
            <Button
              onClick={(): void => {
                void handleImport();
              }}
              disabled={importing}
            >
              {importing ? "Importing..." : "Import products"}
            </Button>
          </div>
        </div>
      </SectionPanel>

      <SectionPanel variant="subtle" className="p-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <h3 className="text-sm font-semibold text-white">
              Import list preview
            </h3>
            <p className="mt-1 text-xs text-gray-400">
              Compare Base products with existing records by Base ID.
            </p>
          </div>
          <div className="flex flex-wrap items-center gap-2">
            <Input
              value={importNameSearch}
              onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                (setImportNameSearch(event.target.value), setImportListPage(1))
              }
              placeholder="Search name..."
              className="h-8 w-48 border-border bg-gray-900 text-xs text-white placeholder:text-gray-500"
            />
            <Input
              value={importSkuSearch}
              onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                (setImportSkuSearch(event.target.value), setImportListPage(1))
              }
              placeholder="Search SKU..."
              className="h-8 w-40 border-border bg-gray-900 text-xs text-white placeholder:text-gray-500"
            />
            <UnifiedSelect
              value={uniqueOnly ? "unique" : "all"}
              onValueChange={(v: string): void =>
                (setUniqueOnly(v === "unique"), setImportListPage(1))
              }
              options={[
                { value: "unique", label: "Unique only" },
                { value: "all", label: "All products" }
              ]}
              className="w-32"
              triggerClassName="h-8 border-border bg-gray-900 text-xs text-white"
            />
            <UnifiedSelect
              value={String(importListPageSize)}
              onValueChange={(value: string): void => {
                const nextSize = Number(value);
                setImportListPageSize(Number.isFinite(nextSize) ? nextSize : 25);
                setImportListPage(1);
              }}
              options={[
                { value: "10", label: "10 / page" },
                { value: "25", label: "25 / page" },
                { value: "50", label: "50 / page" },
                { value: "100", label: "100 / page" }
              ]}
              className="w-32"
              triggerClassName="h-8 border-border bg-gray-900 text-xs text-white"
            />
            <Button
              onClick={(): void => {
                void handleLoadImportList();
              }}
              disabled={loadingImportList}
            >
              {loadingImportList ? "Loading..." : "Load import list"}
            </Button>
          </div>
        </div>

        {importListStats ? (
          <div className="mt-3 flex items-center justify-between text-xs text-gray-400">
            <div>
              Total: {importListStats.total} · Existing:{" "}
              {importListStats.existing} · Available:{" "}
              {importListStats.available ?? importListStats.filtered} · Showing:{" "}
              {importListStats.filtered} · Selected: {selectedImportCount}
              {importListStats.skuDuplicates ? (
                <span className="text-yellow-400">
                  {" "}
                  · SKU duplicates: {importListStats.skuDuplicates}
                </span>
              ) : null}
            </div>
            <Pagination
              page={importListPage}
              totalPages={importListStats.totalPages ?? 1}
              onPageChange={setImportListPage}
              className="scale-90 origin-right"
            />
          </div>
        ) : null}

        {importList.length > 0 ? (
          <SectionPanel variant="subtle-compact" className="mt-3 max-h-96 overflow-auto p-0">
            <div className="grid grid-cols-[28px_50px_100px_1fr_90px_70px_60px_70px] gap-3 border-b border-border px-3 py-2 text-[11px] uppercase tracking-wide text-gray-500 sticky top-0 bg-card z-10">
              <span className="flex items-center">
                <Checkbox
                  aria-label="Select all visible products"
                  checked={
                    allVisibleSelected ||
                    (isSomeVisibleSelected && "indeterminate")
                  }
                  onCheckedChange={(
                    checked: boolean | "indeterminate",
                  ): void => {
                    if (Boolean(checked)) {
                      setSelectedImportIds((prev: Set<string>) => {
                        const next = new Set(prev);
                        importList.forEach((item: ImportListItem) => {
                          if (item.baseProductId) next.add(item.baseProductId);
                        });
                        return next;
                      });
                    } else {
                      setSelectedImportIds((prev: Set<string>) => {
                        const next = new Set(prev);
                        importList.forEach((item: ImportListItem) => {
                          if (item.baseProductId)
                            next.delete(item.baseProductId);
                        });
                        return next;
                      });
                    }
                  }}
                  className="h-3 w-3 rounded border bg-gray-900 text-emerald-500"
                />
              </span>
              <span>Img</span>
              <span>Base ID</span>
              <span>Product</span>
              <span>SKU</span>
              <span>Price</span>
              <span>Qty</span>
              <span>Status</span>
            </div>
            {importList.map((item: ImportListItem) => (
              <div
                key={item.baseProductId}
                className={`grid grid-cols-[28px_50px_100px_1fr_90px_70px_60px_70px] gap-3 border-b border-gray-900/70 px-3 py-2 text-xs text-gray-300 last:border-b-0 items-center transition-colors ${
                  selectedImportIds.has(item.baseProductId)
                    ? "bg-emerald-500/5"
                    : "hover:bg-card/40"
                }`}
              >
                <Checkbox
                  checked={selectedImportIds.has(item.baseProductId)}
                  onCheckedChange={(
                    checked: boolean | "indeterminate",
                  ): void => {
                    const isChecked = Boolean(checked);
                    setSelectedImportIds((prev: Set<string>) => {
                      const next = new Set(prev);
                      if (isChecked) {
                        next.add(item.baseProductId);
                      } else {
                        next.delete(item.baseProductId);
                      }
                      return next;
                    });
                  }}
                  className="h-3 w-3 rounded border bg-gray-900 text-emerald-500"
                  aria-label={`Select ${item.name}`}
                />
                <div className="relative h-10 w-10 overflow-hidden rounded bg-gray-900">
                  {item.image ? (
                    <NextImage
                      src={item.image}
                      alt=""
                      fill
                      className="object-cover"
                      unoptimized={!item.image.includes("baselinker.com")}
                    />
                  ) : (
                    <div className="flex h-full w-full items-center justify-center text-[10px] text-gray-600">
                      No img
                    </div>
                  )}
                </div>
                <span className="truncate text-gray-400 font-mono text-[11px]">
                  {item.baseProductId}
                </span>
                <div className="min-w-0">
                  <div className="truncate font-medium text-gray-200">
                    {item.name}
                  </div>
                  {item.description && (
                    <div className="truncate text-[11px] text-gray-500">
                      {item.description}
                    </div>
                  )}
                </div>
                <span
                  className={`truncate font-mono text-[11px] ${
                    item.skuExists ? "text-yellow-400" : "text-gray-400"
                  }`}
                >
                  {item.sku ?? "—"}
                  {item.skuExists && (
                    <span className="ml-1" title="SKU already exists">
                      ⚠
                    </span>
                  )}
                </span>
                <span className="truncate">{item.price ?? 0}</span>
                <span className="truncate">{item.stock ?? 0}</span>
                <span
                  className={`text-[11px] font-medium ${
                    item.exists
                      ? "text-amber-400"
                      : item.skuExists
                        ? "text-yellow-400"
                        : "text-emerald-400"
                  }`}
                >
                  {item.exists ? "Exists" : item.skuExists ? "SKU dup" : "New"}
                </span>
              </div>
            ))}
          </SectionPanel>
        ) : (
          <p className="mt-3 text-xs text-gray-500">
            {importList.length > 0
              ? "No matches for this search."
              : "No items loaded yet."}
          </p>
        )}
      </SectionPanel>

      {lastResult ? (
        <SectionPanel variant="subtle" className="p-4">
          <h3 className="text-sm font-semibold text-white">
            Last import summary
          </h3>
          <p className="mt-2 text-sm text-gray-300">
            Imported {lastResult.imported} of {lastResult.total} product(s).
          </p>
          {lastResult.failed > 0 ? (
            <p className="mt-1 text-sm text-red-300">
              {lastResult.failed} failed.
            </p>
          ) : null}
          {lastResult.errors?.length ? (
            <div className="mt-3 space-y-1 text-xs text-gray-400">
              {lastResult.errors.map((error: string, index: number) => (
                <p key={`${error}-${index}`}>• {error}</p>
              ))}
            </div>
          ) : null}
        </SectionPanel>
      ) : null}
    </div>
  );
}

"use client";

import React from "react";
import { Label, UnifiedSelect, Checkbox } from "@/shared/ui";
import type { BaseInventory, Template } from "@/features/data-import-export/types/imports";

interface BaseListingSettingsProps {
  inventories: BaseInventory[];
  selectedInventoryId: string;
  onInventoryIdChange: (id: string) => void;
  loadingInventories: boolean;
  templates: Template[];
  selectedTemplateId: string;
  onTemplateIdChange: (id: string) => void;
  allowDuplicateSku: boolean;
  onAllowDuplicateSkuChange: (allowed: boolean) => void;
}

export function BaseListingSettings({
  inventories,
  selectedInventoryId,
  onInventoryIdChange,
  loadingInventories,
  templates,
  selectedTemplateId,
  onTemplateIdChange,
  allowDuplicateSku,
  onAllowDuplicateSkuChange,
}: BaseListingSettingsProps): React.JSX.Element {
  return (
    <div className="space-y-4">
      <div className="space-y-2">
        <Label htmlFor="inventory">
          Base.com Inventory {loadingInventories && "(Loading...)"}
        </Label>
        <UnifiedSelect
          value={selectedInventoryId}
          onValueChange={onInventoryIdChange}
          disabled={loadingInventories || inventories.length === 0}
          options={inventories
            .filter((inventory: BaseInventory): boolean => !!inventory.id)
            .map((inventory: BaseInventory) => ({
              value: inventory.id!,
              label: inventory.name
            }))}
          placeholder="Select inventory..."
        />
        {inventories.length === 0 && !loadingInventories && (
          <p className="text-xs text-red-400">
            No inventories found. Please check your Base.com account.
          </p>
        )}
      </div>

      <div className="space-y-2">
        <Label htmlFor="template">Template (Optional)</Label>
        <UnifiedSelect
          value={selectedTemplateId}
          onValueChange={onTemplateIdChange}
          options={[
            { value: "none", label: "No template" },
            ...templates
              .filter((template: Template): boolean => !!template.id)
              .map((template: Template) => ({
                value: template.id!,
                label: template.name
              }))
          ]}
          placeholder="No template (use defaults)"
        />
        <p className="text-xs text-gray-500">
          Templates define how product fields map to Base.com fields.
        </p>
      </div>

      <div className="flex items-center gap-2 pt-2">
        <Checkbox
          id="allowDuplicateSku"
          checked={allowDuplicateSku} 
          onCheckedChange={(checked: boolean | "indeterminate"): void => onAllowDuplicateSkuChange(Boolean(checked))}
          className="h-4 w-4 rounded border bg-gray-900 text-blue-500"
        />
        <Label htmlFor="allowDuplicateSku" className="text-sm text-gray-300">
          Allow duplicate SKUs
        </Label>
      </div>
      <p className="text-xs text-gray-500">
        When unchecked, export will fail if the SKU already exists in the Base.com inventory.
      </p>
    </div>
  );
}

"use client";

import { SharedModal, UnifiedSelect, Button, Label, SectionPanel } from "@/shared/ui";
import { useIntegrationSelection } from "./hooks/useIntegrationSelection";
import type { IntegrationWithConnections, IntegrationConnectionBasic } from "@/features/integrations/types/listings";
import Link from "next/link";

export type SelectIntegrationModalProps = {
  onClose: () => void;
  onSelect: (integrationId: string, connectionId: string) => void;
};

export default function SelectIntegrationModal({
  onClose,
  onSelect,
}: SelectIntegrationModalProps): React.JSX.Element {
  const {
    integrations,
    loading,
    selectedIntegrationId,
    selectedConnectionId,
    selectedIntegration,
    setSelectedIntegrationId,
    setSelectedConnectionId,
  } = useIntegrationSelection();

  // Note: We don't auto-select the integration on initial load
  // The user should manually select the integration, and then we auto-select the connection

  const handleContinue = (): void => {
    if (selectedIntegrationId && selectedConnectionId) {
      onSelect(selectedIntegrationId, selectedConnectionId);
    }
  };

  return (
    <SharedModal
      open={true}
      onClose={onClose}
      title="Select Marketplace / Integration"
      size="md"
    >
        <div className="space-y-4">
        {loading ? (
          <p className="text-sm text-gray-400">Loading integrations...</p>
        ) : integrations.length === 0 ? (
          <SectionPanel variant="subtle" className="border-yellow-500/40 bg-yellow-500/10 p-6 text-center">
            <p className="text-sm text-yellow-200">No connected integrations</p>
            <p className="mt-2 text-xs text-yellow-300/70">
              <Link href="/admin/integrations" className="underline hover:text-yellow-100">
                Set up an integration first
              </Link>
            </p>
          </SectionPanel>
        ) : (
          <>
            <div>
              <Label className="mb-2 block text-sm font-medium text-gray-300">
                Integration
              </Label>
              <UnifiedSelect
                value={selectedIntegrationId}
                onValueChange={(value: string): void => setSelectedIntegrationId(value)}
                options={integrations
                  .filter((integration: IntegrationWithConnections): boolean => !!integration.id)
                  .map((integration: IntegrationWithConnections) => ({
                    value: integration.id!,
                    label: integration.name
                  }))}
                placeholder="Select an integration..."
              />
            </div>

            {selectedIntegration && selectedIntegration.connections.length > 0 && (
              <div>
                <Label className="mb-2 block text-sm font-medium text-gray-300">
                  Account / Connection
                </Label>
                <UnifiedSelect
                  value={selectedConnectionId}
                  onValueChange={(value: string): void => setSelectedConnectionId(value)}
                  options={selectedIntegration.connections
                    .filter((connection: IntegrationConnectionBasic): boolean => !!connection.id)
                    .map((connection: IntegrationConnectionBasic) => ({
                      value: connection.id!,
                      label: connection.name
                    }))}
                  placeholder="Select an account..."
                />
              </div>
            )}

            <div className="flex justify-end gap-3 pt-4">
              <Button
                type="button"
                onClick={onClose}
                className="rounded-md px-4 py-2 text-sm text-gray-400 hover:text-white transition-colors"
              >
                Cancel
              </Button>
              <Button
                type="button"
                onClick={handleContinue}
                disabled={!selectedIntegrationId || !selectedConnectionId}
                className="rounded-md bg-primary px-4 py-2 text-sm font-semibold text-primary-foreground hover:bg-primary/90 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                Continue
              </Button>
            </div>
          </>
        )}
        </div>
    </SharedModal>
  );
}

import { useToast, Button, Label, UnifiedSelect } from "@/shared/ui";
import React, { useCallback, useEffect, useMemo, useState, useRef } from "react";
import { Download, RefreshCw, Save, ChevronRight, ChevronDown, Check } from "lucide-react";
import { logClientError } from "@/features/observability";

import type { ExternalCategory, CategoryMappingWithDetails } from "@/features/integrations/types/category-mapping";
import type { Catalog } from "@/features/products";

import { useCatalogs } from "@/features/products/hooks/useCatalogQueries";
import { useProductCategories } from "@/features/products/hooks/useCategoryQueries";
import { useExternalCategories, useCategoryMappings } from "@/features/integrations/hooks/useMarketplaceQueries";
import { useFetchExternalCategoriesMutation, useSaveMappingsMutation } from "@/features/integrations/hooks/useMarketplaceMutations";

type BaseCategoryMapperProps = {
  connectionId: string;
  connectionName: string;
};

export function BaseCategoryMapper({ connectionId, connectionName }: BaseCategoryMapperProps): React.JSX.Element {
  const { toast } = useToast();

  // Queries
  const catalogsQuery = useCatalogs();
  const catalogs = useMemo(() => catalogsQuery.data ?? [], [catalogsQuery.data]);
  const catalogsLoading = catalogsQuery.isLoading;

  const [selectedCatalogId, setSelectedCatalogId] = useState<string | null>(null);
  const hasInitializedCatalog = useRef(false);

  // Auto-select default catalog
  useEffect(() => {
    let timer: NodeJS.Timeout | null = null;
    if (!selectedCatalogId && catalogs.length > 0 && !hasInitializedCatalog.current) {
      const defaultCatalog = catalogs.find((c: Catalog) => c.isDefault) ?? catalogs[0];
      if (defaultCatalog) {
        timer = setTimeout(() => {
          setSelectedCatalogId(defaultCatalog.id);
          hasInitializedCatalog.current = true;
        }, 0);
      }
    }
    return (): void => {
      if (timer) clearTimeout(timer);
    };
  }, [catalogs, selectedCatalogId]);

  const internalCategoriesQuery = useProductCategories(selectedCatalogId ?? undefined);
  const internalCategories = internalCategoriesQuery.data ?? [];
  const internalCategoriesLoading = internalCategoriesQuery.isLoading;

  const externalCategoriesQuery = useExternalCategories(connectionId);
  const externalCategories = useMemo(() => externalCategoriesQuery.data ?? [], [externalCategoriesQuery.data]);
  const externalCategoriesLoading = externalCategoriesQuery.isLoading;

  const mappingsQuery = useCategoryMappings(connectionId, selectedCatalogId);
  const mappings = useMemo(() => mappingsQuery.data ?? [], [mappingsQuery.data]);
  const mappingsLoading = mappingsQuery.isLoading;

  // Mutations
  const fetchMutation = useFetchExternalCategoriesMutation();
  const saveMutation = useSaveMappingsMutation();

  const [pendingMappings, setPendingMappings] = useState<Map<string, string>>(new Map());
  const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());
  const hasInitializedExpansion = useRef(false);

  // Initialize expansion state
  useEffect(() => {
    let timer: NodeJS.Timeout | null = null;
    if (externalCategories.length > 0 && !hasInitializedExpansion.current) {
      timer = setTimeout(() => {
        setExpandedIds((prev: Set<string>) => {
          // If we haven't initialized yet (or just reset), expand depth 0
          if (prev.size === 0) {
            return new Set(
              externalCategories
                .filter((c: ExternalCategory) => c.depth === 0)
                .map((c: ExternalCategory) => c.id)
            );
          }
          return prev;
        });
        hasInitializedExpansion.current = true;
      }, 0);
    }
    return (): void => {
      if (timer) clearTimeout(timer);
    };
  }, [externalCategories]);

  // Reset pending mappings when catalog changes
  useEffect(() => {
    const timer = setTimeout(() => {
      setPendingMappings(new Map());
    }, 0);
    return (): void => clearTimeout(timer);
  }, [selectedCatalogId]);

  // Fetch categories from Base.com API
  const handleFetchFromBase = async (): Promise<void> => {
    try {
      const result = await fetchMutation.mutateAsync({ connectionId });
      toast(result.message, { variant: "success" });
    } catch (error: unknown) {
      logClientError(error, { context: { source: "BaseCategoryMapper", action: "fetchFromBase", connectionId } });
      const message = error instanceof Error ? error.message : "Failed to fetch categories";
      toast(message, { variant: "error" });
    }
  };

  // Get current mapping for an external category
  const getMappingForExternal = useCallback(
    (externalCategoryId: string): string | null => {
      // Check pending mappings first
      if (pendingMappings.has(externalCategoryId)) {
        return pendingMappings.get(externalCategoryId) ?? null;
      }
      // Check saved mappings
      const mapping = mappings.find((m: CategoryMappingWithDetails) => m.externalCategoryId === externalCategoryId);
      return mapping?.internalCategoryId ?? null;
    },
    [mappings, pendingMappings]
  );

  // Handle mapping change
  const handleMappingChange = (externalCategoryId: string, internalCategoryId: string | null): void => {
    setPendingMappings((prev: Map<string, string>) => {
      const next = new Map(prev);
      if (internalCategoryId) {
        next.set(externalCategoryId, internalCategoryId);
      } else {
        next.delete(externalCategoryId);
      }
      return next;
    });
  };

  // Save all pending mappings
  const handleSave = async (): Promise<void> => {
    if (pendingMappings.size === 0 || !selectedCatalogId) {
      toast("No changes to save", { variant: "info" });
      return;
    }

    try {
      const mappingsToSave = Array.from(pendingMappings.entries()).map(
        ([externalCategoryId, internalCategoryId]: [string, string]) => ({
          externalCategoryId,
          internalCategoryId,
        })
      );

      const result = await saveMutation.mutateAsync({
        connectionId,
        catalogId: selectedCatalogId,
        mappings: mappingsToSave,
      });

      toast(result.message, { variant: "success" });
      setPendingMappings(new Map());
    } catch (error: unknown) {
      logClientError(error, { context: { source: "BaseCategoryMapper", action: "saveMappings", connectionId, catalogId: selectedCatalogId } });
      const message = error instanceof Error ? error.message : "Failed to save mappings";
      toast(message, { variant: "error" });
    }
  };

  // Toggle category expansion
  const toggleExpand = (categoryId: string): void => {
    setExpandedIds((prev: Set<string>) => {
      const next = new Set(prev);
      if (next.has(categoryId)) {
        next.delete(categoryId);
      } else {
        next.add(categoryId);
      }
      return next;
    });
  };

  // Build tree structure for display
  const categoryTree = useMemo((): ExternalCategory[] => {
    const buildLevel = (parentExternalId: string | null): ExternalCategory[] => {
      return externalCategories
        .filter((c: ExternalCategory) => c.parentExternalId === parentExternalId)
        .sort((a: ExternalCategory, b: ExternalCategory) => a.name.localeCompare(b.name));
    };

    return buildLevel(null);
  }, [externalCategories]);

  // Count statistics
  const stats = useMemo((): { total: number; mapped: number; pending: number } => {
    const total = externalCategories.length;
    const mapped = externalCategories.filter((c: ExternalCategory) => getMappingForExternal(c.id) !== null).length;
    const pending = pendingMappings.size;
    return { total, mapped, pending };
  }, [externalCategories, getMappingForExternal, pendingMappings.size]);

  // Render category row with children
  const renderCategory = (category: ExternalCategory, depth: number = 0): React.JSX.Element => {
    const children = externalCategories.filter((c: ExternalCategory) => c.parentExternalId === category.externalId);
    const hasChildren = children.length > 0;
    const isExpanded = expandedIds.has(category.id);
    const currentMapping = getMappingForExternal(category.id);
    const hasPendingChange = pendingMappings.has(category.id);

    return (
      <React.Fragment key={category.id}>
        <tr className={`border-b border-border ${hasPendingChange ? "bg-yellow-500/5" : ""}`}>
          <td className="px-4 py-2">
            <div className="flex items-center" style={{ paddingLeft: `${depth * 20}px` }}>
              {hasChildren ? (
                <Button
                  onClick={(): void => toggleExpand(category.id)}
                  className="mr-2 rounded p-0.5 text-gray-400 hover:bg-muted/50 hover:text-white"
                >
                  {isExpanded ? (
                    <ChevronDown className="h-4 w-4" />
                  ) : (
                    <ChevronRight className="h-4 w-4" />
                  )}
                </Button>
              ) : (
                <span className="mr-2 w-5" />
              )}
              <span className="text-sm text-gray-200">{category.name}</span>
              {currentMapping && (
                <Check className="ml-2 h-3 w-3 text-emerald-400" />
              )}
            </div>
          </td>
          <td className="px-4 py-2">
            <UnifiedSelect
              value={currentMapping ?? "__unmapped__"}
              onValueChange={(v: string): void =>
                handleMappingChange(category.id, v === "__unmapped__" ? null : v)
              }
              disabled={internalCategoriesLoading || !selectedCatalogId}
              options={[
                { value: "__unmapped__", label: "— Not mapped —" },
                ...internalCategories.map(ic => ({ value: ic.id, label: ic.name }))
              ]}
              triggerClassName="w-full bg-gray-800 border-border text-white text-sm h-8"
            />
          </td>
        </tr>
        {hasChildren && isExpanded && (
          <React.Fragment>
            {children
              .sort((a: ExternalCategory, b: ExternalCategory) => a.name.localeCompare(b.name))
              .map((child: ExternalCategory) => renderCategory(child, depth + 1))}
          </React.Fragment>
        )}
      </React.Fragment>
    );
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-semibold text-white">
            Base.com Categories
          </h2>
          <p className="text-sm text-gray-400">
            Connection: {connectionName}
          </p>
        </div>

        <div className="flex items-center gap-3">
          <Button
            onClick={(): void => { void handleFetchFromBase(); }}
            disabled={fetchMutation.isPending}
            className="flex items-center gap-2 rounded-md border bg-gray-800 px-4 py-2 text-sm text-white hover:bg-gray-700 disabled:opacity-50"
          >
            {fetchMutation.isPending ? (
              <RefreshCw className="h-4 w-4 animate-spin" />
            ) : (
              <Download className="h-4 w-4" />
            )}
            {fetchMutation.isPending ? "Fetching..." : "Fetch Categories"}
          </Button>

          <Button
            onClick={(): void => { void handleSave(); }}
            disabled={saveMutation.isPending || pendingMappings.size === 0}
            className="flex items-center gap-2 rounded-md bg-emerald-600 px-4 py-2 text-sm font-medium text-white hover:bg-emerald-500 disabled:opacity-50"
          >
            {saveMutation.isPending ? (
              <RefreshCw className="h-4 w-4 animate-spin" />
            ) : (
              <Save className="h-4 w-4" />
            )}
            {saveMutation.isPending ? "Saving..." : `Save (${pendingMappings.size})`}
          </Button>
        </div>
      </div>

      {/* Catalog Selector */}
      <div className="flex items-center gap-4">
        <Label className="text-sm text-gray-400">Target Catalog:</Label>
        <div className="w-[200px]">
          <UnifiedSelect
            value={selectedCatalogId ?? "__none__"}
            onValueChange={(v: string): void => setSelectedCatalogId(v === "__none__" ? null : v)}
            disabled={catalogsLoading}
            options={[
              ...(!catalogsLoading && catalogs.length === 0 ? [{ value: "__none__", label: "No catalogs available" }] : []),
              ...catalogs.map(catalog => ({ value: catalog.id, label: catalog.name }))
            ]}
            placeholder={catalogsLoading ? "Loading..." : "Select catalog"}
            triggerClassName="bg-gray-800 border-border text-white text-sm h-9"
          />
        </div>

        {selectedCatalogId && (
          <span className="text-xs text-gray-500">
            {internalCategories.length} internal categories
          </span>
        )}
      </div>

      {/* Stats */}
      <div className="flex gap-6 text-sm">
        <div className="text-gray-400">
          Total: <span className="text-white">{stats.total}</span>
        </div>
        <div className="text-gray-400">
          Mapped: <span className="text-emerald-400">{stats.mapped}</span>
        </div>
        {stats.pending > 0 && (
          <div className="text-gray-400">
            Unsaved changes: <span className="text-yellow-400">{stats.pending}</span>
          </div>
        )}
      </div>

      {/* Category Table */}
      <div className="overflow-hidden rounded-md border border-border">
        <table className="w-full">
          <thead>
            <tr className="border-b border-border bg-card/50">
              <th className="px-4 py-3 text-left text-xs font-medium uppercase text-gray-400">
                External Category
              </th>
              <th className="px-4 py-3 text-left text-xs font-medium uppercase text-gray-400">
                Internal Category
              </th>
            </tr>
          </thead>
          <tbody>
            {externalCategoriesLoading || mappingsLoading ? (
              <tr>
                <td colSpan={2} className="px-4 py-8 text-center text-gray-500">
                  Loading categories...
                </td>
              </tr>
            ) : externalCategories.length === 0 ? (
              <tr>
                <td colSpan={2} className="px-4 py-8 text-center text-gray-500">
                  No external categories found. Click &quot;Fetch Categories&quot; to load from Base.com.
                </td>
              </tr>
            ) : (
              categoryTree.map((category: ExternalCategory) => renderCategory(category, 0))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

